#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="D:\NEW folder\New folder\krishi\krishi-sahayak-main\krishi-sahayak-main\node_modules\lan-network\dist\node_modules;D:\NEW folder\New folder\krishi\krishi-sahayak-main\krishi-sahayak-main\node_modules\lan-network\node_modules;D:\NEW folder\New folder\krishi\krishi-sahayak-main\krishi-sahayak-main\node_modules;D:\NEW folder\New folder\krishi\krishi-sahayak-main\node_modules;D:\NEW folder\New folder\krishi\node_modules;D:\NEW folder\New folder\node_modules;D:\NEW folder\node_modules;D:\node_modules;D:\NEW folder\New folder\krishi\krishi-sahayak-main\krishi-sahayak-main\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/d/NEW folder/New folder/krishi/krishi-sahayak-main/krishi-sahayak-main/node_modules/lan-network/dist/node_modules:/mnt/d/NEW folder/New folder/krishi/krishi-sahayak-main/krishi-sahayak-main/node_modules/lan-network/node_modules:/mnt/d/NEW folder/New folder/krishi/krishi-sahayak-main/krishi-sahayak-main/node_modules:/mnt/d/NEW folder/New folder/krishi/krishi-sahayak-main/node_modules:/mnt/d/NEW folder/New folder/krishi/node_modules:/mnt/d/NEW folder/New folder/node_modules:/mnt/d/NEW folder/node_modules:/mnt/d/node_modules:/mnt/d/NEW folder/New folder/krishi/krishi-sahayak-main/krishi-sahayak-main/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../lan-network/dist/lan-network-cli.js" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../lan-network/dist/lan-network-cli.js" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../lan-network/dist/lan-network-cli.js" $args
  } else {
    & "node$exe"  "$basedir/../lan-network/dist/lan-network-cli.js" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
